    #[test]
    fn s05_reference_contract_deferred_utilities_are_disabled_and_ids_are_unique() {
        let entries = TOOL_GROUPS
            .iter()
            .flat_map(|group| group.entries.iter())
            .collect::<Vec<_>>();

        let mut seen_tool_ids = HashSet::new();
        for entry in &entries {
            assert!(
                seen_tool_ids.insert(entry.id.as_str()),
                "duplicate tool action id: {}",
                entry.id.as_str()
            );
        }

        let deferred_entries = entries
            .iter()
            .filter_map(|entry| {
                entry
                    .deferred_utility()
                    .map(|utility| (entry.label, utility))
            })
            .collect::<Vec<_>>();
        assert_eq!(
            deferred_entries,
            [
